8237 VPRecipeBase *
8238 VPRecipeBuilder::tryToCreateWidenNonPhiRecipe(VPSingleDefRecipe *R,
8239                                               VFRange &Range) {
8240   assert(!R->isPhi() && "phis must be handled earlier");
8241   // First, check for specific widening recipes that deal with optimizing
8242   // truncates, calls and memory operations.
8243 
8244   VPRecipeBase *Recipe;
8245   auto *VPI = cast<VPInstruction>(R);
8246   if (VPI->getOpcode() == Instruction::Trunc &&
8247       (Recipe = tryToOptimizeInductionTruncate(VPI, Range)))
8248     return Recipe;
8249 
8250   // All widen recipes below deal only with VF > 1.
8251   if (LoopVectorizationPlanner::getDecisionAndClampRange(
8252           [&](ElementCount VF) { return VF.isScalar(); }, Range))
8253     return nullptr;
8254 
8255   if (VPI->getOpcode() == Instruction::Call)
8256     return tryToWidenCall(VPI, Range);
8257 
8258   Instruction *Instr = R->getUnderlyingInstr();
8259   if (VPI->getOpcode() == Instruction::Store)
8260     if (auto HistInfo = Legal->getHistogramInfo(cast<StoreInst>(Instr)))
8261       return tryToWidenHistogram(*HistInfo, VPI);
8262 
8263   if (VPI->getOpcode() == Instruction::Load ||
8264       VPI->getOpcode() == Instruction::Store)
8265     return tryToWidenMemory(VPI, Range);
8266 
8267   if (std::optional<unsigned> ScaleFactor = getScalingForReduction(Instr))
8268     return tryToCreatePartialReduction(VPI, ScaleFactor.value());
8269 
8270   if (!shouldWiden(Instr, Range))
8271     return nullptr;
8272 
8273   if (VPI->getOpcode() == Instruction::GetElementPtr)
8274     return new VPWidenGEPRecipe(cast<GetElementPtrInst>(Instr), R->operands(),
8275                                 *VPI, VPI->getDebugLoc());
8276 
8277   if (Instruction::isCast(VPI->getOpcode())) {
8278     auto *CI = cast<CastInst>(Instr);
8279     auto *CastR = cast<VPInstructionWithType>(VPI);
8280     return new VPWidenCastRecipe(CI->getOpcode(), VPI->getOperand(0),
