8289 VPRecipeBuilder::tryToCreatePartialReduction(VPInstruction *Reduction,
8290                                              unsigned ScaleFactor) {
8291   assert(Reduction->getNumOperands() == 2 &&
8292          "Unexpected number of operands for partial reduction");
