8294   VPValue *BinOp = Reduction->getOperand(0);
8295   VPValue *Accumulator = Reduction->getOperand(1);
8296   VPRecipeBase *BinOpRecipe = BinOp->getDefiningRecipe();
8297   if (isa<VPReductionPHIRecipe>(BinOpRecipe) ||
8298       (isa<VPReductionRecipe>(BinOpRecipe) &&
8299        cast<VPReductionRecipe>(BinOpRecipe)->isPartialReduction()))
8300     std::swap(BinOp, Accumulator);
8301 
8302   if (auto *RedPhiR = dyn_cast<VPReductionPHIRecipe>(Accumulator))
8303     RedPhiR->setVFScaleFactor(ScaleFactor);
8304 
8305   assert(ScaleFactor ==
8306              vputils::getVFScaleFactor(Accumulator->getDefiningRecipe()) &&
8307          "all accumulators in chain must have same scale factor");
8308 
8309   auto *ReductionI = Reduction->getUnderlyingInstr();
8310   assert(
8311       Reduction->getOpcode() != Instruction::FAdd ||
8312       (ReductionI->hasAllowReassoc() && ReductionI->hasAllowContract()) &&
8313           "FAdd partial reduction requires allow-reassoc and allow-contract");
8314   if (Reduction->getOpcode() == Instruction::Sub) {
8315     SmallVector<VPValue *, 2> Ops;
8316     Ops.push_back(Plan.getConstantInt(ReductionI->getType(), 0));
8317     Ops.push_back(BinOp);
8318     BinOp = new VPWidenRecipe(*ReductionI, Ops, VPIRFlags(*ReductionI),
8319                               VPIRMetadata(), ReductionI->getDebugLoc());
8320     Builder.insert(BinOp->getDefiningRecipe());
8321   }
8322 
8323   VPValue *Cond = nullptr;
8324   if (CM.blockNeedsPredicationForAnyReason(ReductionI->getParent()))
8325     Cond = getBlockInMask(Builder.getInsertBlock());
