8102 bool VPRecipeBuilder::getScaledReductions(
8103     Instruction *PHI, Instruction *RdxExitInstr, VFRange &Range,
8104     SmallVectorImpl<std::pair<PartialReductionChain, unsigned>> &Chains) {
8105   if (!CM.TheLoop->contains(RdxExitInstr))
8106     return false;
8107 
8108   auto *Update = dyn_cast<BinaryOperator>(RdxExitInstr);
8109   if (!Update)
8110     return false;
8111 
8112   Value *Op = Update->getOperand(0);
8113   Value *PhiOp = Update->getOperand(1);
8114   if (Op == PHI)
8115     std::swap(Op, PhiOp);
8116 
8117   using namespace llvm::PatternMatch;
8118   // If Op is an extend, then it's still a valid partial reduction if the
8119   // extended mul fulfills the other requirements.
8120   // For example, reduce.add(ext(mul(ext(A), ext(B)))) is still a valid partial
8121   // reduction since the inner extends will be widened. We already have oneUse
8122   // checks on the inner extends so widening them is safe.
8123   std::optional<TTI::PartialReductionExtendKind> OuterExtKind = std::nullopt;
8124   if (match(Op, m_ZExtOrSExt(m_Mul(m_Value(), m_Value())))) {
8125     auto *Cast = cast<CastInst>(Op);
8126     OuterExtKind = TTI::getPartialReductionExtendKind(Cast->getOpcode());
8127     Op = Cast->getOperand(0);
8128   }
8129 
8130   // Try and get a scaled reduction from the first non-phi operand.
8131   // If one is found, we use the discovered reduction instruction in
8132   // place of the accumulator for costing.
8133   if (auto *OpInst = dyn_cast<Instruction>(Op)) {
8134     if (getScaledReductions(PHI, OpInst, Range, Chains)) {
8135       PHI = Chains.rbegin()->first.Reduction;
8136 
8137       Op = Update->getOperand(0);
8138       PhiOp = Update->getOperand(1);
8139       if (Op == PHI)
8140         std::swap(Op, PhiOp);
8141     }
8142   }
8143   if (PhiOp != PHI)
8144     return false;
8145 
8146   // If the update is a binary operator, check both of its operands to see if
8147   // they are extends. Otherwise, see if the update comes directly from an
8148   // extend.
8149   Instruction *Exts[2] = {nullptr};
8150   BinaryOperator *ExtendUser = dyn_cast<BinaryOperator>(Op);
8151   std::optional<unsigned> BinOpc;
8152   Type *ExtOpTypes[2] = {nullptr};
8153   TTI::PartialReductionExtendKind ExtKinds[2] = {TTI::PR_None};
8154 
8155   auto CollectExtInfo = [this, OuterExtKind, &Exts, &ExtOpTypes,
8156                          &ExtKinds](SmallVectorImpl<Value *> &Ops) -> bool {
8157     for (const auto &[I, OpI] : enumerate(Ops)) {
8158       const APInt *C;
8159       if (I > 0 && match(OpI, m_APInt(C)) &&
8160           canConstantBeExtended(C, ExtOpTypes[0], ExtKinds[0])) {
8161         ExtOpTypes[I] = ExtOpTypes[0];
8162         ExtKinds[I] = ExtKinds[0];
8163         continue;
8164       }
8165       Value *ExtOp;
8166       if (!match(OpI, m_ZExtOrSExt(m_Value(ExtOp))) &&
8167           !match(OpI, m_FPExt(m_Value(ExtOp))))
8168         return false;
8169       Exts[I] = cast<Instruction>(OpI);
8170 
8171       // TODO: We should be able to support live-ins.
8172       if (!CM.TheLoop->contains(Exts[I]))
8173         return false;
8174 
8175       ExtOpTypes[I] = ExtOp->getType();
8176       ExtKinds[I] = TTI::getPartialReductionExtendKind(Exts[I]);
8177       // The outer extend kind must be the same as the inner extends, so that
8178       // they can be folded together.
8179       if (OuterExtKind.has_value() && OuterExtKind.value() != ExtKinds[I])
8180         return false;
8181     }
8182     return true;
8183   };
8184 
8185   if (ExtendUser) {
8186     if (!ExtendUser->hasOneUse())
8187       return false;
8188 
8189     // Use the side-effect of match to replace BinOp only if the pattern is
8190     // matched, we don't care at this point whether it actually matched.
8191     match(ExtendUser, m_Neg(m_BinOp(ExtendUser)));
8192 
8193     SmallVector<Value *> Ops(ExtendUser->operands());
8194     if (!CollectExtInfo(Ops))
8195       return false;
8196 
8197     BinOpc = std::make_optional(ExtendUser->getOpcode());
8198   } else if (match(Update, m_Add(m_Value(), m_Value())) ||
8199              match(Update, m_FAdd(m_Value(), m_Value()))) {
8200     // We already know the operands for Update are Op and PhiOp.
8201     SmallVector<Value *> Ops({Op});
8202     if (!CollectExtInfo(Ops))
8203       return false;
8204 
8205     ExtendUser = Update;
8206     BinOpc = std::nullopt;
8207   } else
8208     return false;
8209 
8210   PartialReductionChain Chain(RdxExitInstr, Exts[0], Exts[1], ExtendUser);
8211 
8212   TypeSize PHISize = PHI->getType()->getPrimitiveSizeInBits();
8213   TypeSize ASize = ExtOpTypes[0]->getPrimitiveSizeInBits();
8214   if (!PHISize.hasKnownScalarFactor(ASize))
8215     return false;
8216   unsigned TargetScaleFactor = PHISize.getKnownScalarFactor(ASize);
8217 
8218   if (LoopVectorizationPlanner::getDecisionAndClampRange(
8219           [&](ElementCount VF) {
8220             std::optional<FastMathFlags> FMF = std::nullopt;
8221             if (Update->getOpcode() == Instruction::FAdd)
8222               FMF = Update->getFastMathFlags();
8223             InstructionCost Cost = TTI->getPartialReductionCost(
8224                 Update->getOpcode(), ExtOpTypes[0], ExtOpTypes[1],
8225                 PHI->getType(), VF, ExtKinds[0], ExtKinds[1], BinOpc,
8226                 CM.CostKind, FMF);
8227             return Cost.isValid();
8228           },
8229           Range)) {
8230     Chains.emplace_back(Chain, TargetScaleFactor);
8231     return true;
8232   }
8233 
8234   return false;
8235 }
