2913         cast<VPReductionRecipe>(ExpressionRecipes[1])->getRecurrenceKind());
2914     auto *ExtR = cast<VPWidenCastRecipe>(ExpressionRecipes[0]);
2915     auto *RedR = cast<VPReductionRecipe>(ExpressionRecipes.back());
