2930       return InstructionCost::getInvalid();
2931   }
2932   case ExpressionTypes::MulAccReduction:
2933     return Ctx.TTI.getMulAccReductionCost(false, Opcode, RedTy, SrcVecTy,
2934                                           Ctx.CostKind);
