8034 /// Find all possible partial reductions in the loop and track all of those that
8035 /// are valid so recipes can be formed later.
8036 void VPRecipeBuilder::collectScaledReductions(VFRange &Range) {
8037   // Find all possible partial reductions, grouping chains by their PHI. This
8038   // grouping allows invalidating the whole chain, if any link is not a valid
8039   // partial reduction.
8040   MapVector<Instruction *,
8041             SmallVector<std::pair<PartialReductionChain, unsigned>>>
8042       ChainsByPhi;
8043   for (const auto &[Phi, RdxDesc] : Legal->getReductionVars()) {
8044     if (Instruction *RdxExitInstr = RdxDesc.getLoopExitInstr())
8045       getScaledReductions(Phi, RdxExitInstr, Range, ChainsByPhi[Phi]);
8046   }
8047 
8048   // A partial reduction is invalid if any of its extends are used by
8049   // something that isn't another partial reduction. This is because the
8050   // extends are intended to be lowered along with the reduction itself.
8051 
8052   // Build up a set of partial reduction ops for efficient use checking.
8053   SmallPtrSet<User *, 4> PartialReductionOps;
8054   for (const auto &[_, Chains] : ChainsByPhi)
8055     for (const auto &[PartialRdx, _] : Chains)
8056       PartialReductionOps.insert(PartialRdx.ExtendUser);
8057 
8058   auto ExtendIsOnlyUsedByPartialReductions =
8059       [&PartialReductionOps](Instruction *Extend) {
8060         return all_of(Extend->users(), [&](const User *U) {
8061           return PartialReductionOps.contains(U);
8062         });
8063       };
8064 
8065   // Check if each use of a chain's two extends is a partial reduction
8066   // and only add those that don't have non-partial reduction users.
8067   for (const auto &[_, Chains] : ChainsByPhi) {
8068     for (const auto &[Chain, Scale] : Chains) {
8069       if (ExtendIsOnlyUsedByPartialReductions(Chain.ExtendA) &&
8070           (!Chain.ExtendB ||
8071            ExtendIsOnlyUsedByPartialReductions(Chain.ExtendB)))
8072         ScaledReductionMap.try_emplace(Chain.Reduction, Scale);
8073     }
8074   }
8075 
8076   // Check that all partial reductions in a chain are only used by other
8077   // partial reductions with the same scale factor. Otherwise we end up creating
8078   // users of scaled reductions where the types of the other operands don't
8079   // match.
8080   for (const auto &[Phi, Chains] : ChainsByPhi) {
8081     for (const auto &[Chain, Scale] : Chains) {
8082       auto AllUsersPartialRdx = [ScaleVal = Scale, RdxPhi = Phi,
8083                                  this](const User *U) {
8084         auto *UI = cast<Instruction>(U);
8085         if (isa<PHINode>(UI) && UI->getParent() == OrigLoop->getHeader())
8086           return UI == RdxPhi;
8087         return ScaledReductionMap.lookup_or(UI, 0) == ScaleVal ||
8088                !OrigLoop->contains(UI->getParent());
8089       };
8090 
8091       // If any partial reduction entry for the phi is invalid, invalidate the
8092       // whole chain.
8093       if (!all_of(Chain.Reduction->users(), AllUsersPartialRdx)) {
8094         for (const auto &[Chain, _] : Chains)
8095           ScaledReductionMap.erase(Chain.Reduction);
8096         break;
8097       }
8098     }
8099   }
8100 }
