5941 
5942   // i8 -> i32 is natively supported for udot/sdot/usdot, both for NEON and SVE.
5943   if (ST->isSVEorStreamingSVEAvailable() ||
5944       (AccumLT.second.isFixedLengthVector() && ST->isNeonAvailable() &&
