5968 AArch64TTIImpl::getShuffleCost(TTI::ShuffleKind Kind, VectorType *DstTy,
5969                                VectorType *SrcTy, ArrayRef<int> Mask,
5970                                TTI::TargetCostKind CostKind, int Index,
