6007     unsigned LTNumElts = LT.second.getVectorNumElements();
6008     unsigned NumVecs = (TpNumElts + LTNumElts - 1) / LTNumElts;
6009     VectorType *NTp = VectorType::get(SrcTy->getScalarType(),
6010                                       LT.second.getVectorElementCount());
