5737   if (Opcode == Instruction::Add && VecVT.isSimple() && ResVT.isSimple() &&
5738       VecVT.getSizeInBits() >= 64) {
5739     std::pair<InstructionCost, MVT> LT = getTypeLegalizationCost(VecTy);
